// ─────────────────────────────────────────────────────────────────
// lib/authority-sections.ts
// Type-specific FAQs (6 per bucket) + Common Mistakes sections
// Used in content-generator.ts to deepen page authority
// ─────────────────────────────────────────────────────────────────

import type { CityData } from './seo-data';
import type { ContentSection, FaqItem } from './content-generator';

type BucketDef = { key: string; matches: string[] };

function classify(type: string, buckets: BucketDef[]): string {
  for (const b of buckets) {
    if (b.matches.some((m) => type.includes(m))) return b.key;
  }
  return 'default';
}

// ─────────────────────────────────────────────────────────────────
// BILL-CHECK FAQs
// ─────────────────────────────────────────────────────────────────
function billCheckFaqs(type: string, city: CityData): FaqItem[] {
  const buckets: BucketDef[] = [
    { key: 'app',         matches: ['via-app', 'android', 'iphone'] },
    { key: 'messaging',   matches: ['via-sms', 'via-whatsapp'] },
    { key: 'dispute',     matches: ['high-bill', 'arrears', 'outstanding', 'overdue', 'unpaid'] },
    { key: 'residential', matches: ['residential', 'domestic'] },
    { key: 'commercial',  matches: ['commercial', 'industrial'] },
    { key: 'meter',       matches: ['meter-reading', 'billing-cycle', 'consumption-bill'] },
    { key: 'download',    matches: ['download-bill', 'get-bill-copy', 'get-gas-bill', 'monthly-gas'] },
    { key: 'history',     matches: ['previous-bill', 'last-month', 'current-month', '2024', '2025', 'quarterly'] },
    { key: 'month',       matches: ['january','february','march','april','may','june','july','august','september','october','november','december'] },
  ];
  const bucket = classify(type, buckets);
  const map: Record<string, FaqItem[]> = {
    app: [
      { q: `Does the SNGPL app work offline for ${city.name} consumers?`, a: `Yes. The SNGPL Consumer App caches the most recently downloaded bill, so you can view it without an active internet connection. However, to fetch a new bill or update your account, an internet connection is required.` },
      { q: `How do I add a second SNGPL consumer number in the app?`, a: `Open the SNGPL app, go to "My Connections" or the profile menu, and select "Add Connection." Enter the second consumer number and verify via OTP. You can then switch between connections in ${city.name} from a single app account.` },
      { q: `Why does the SNGPL app show a different bill amount than the portal?`, a: `Both sources pull from the same SNGPL billing database. If amounts differ, it is usually a caching delay in the app. Force-close the app, reopen it, and refresh your bill. If the discrepancy persists after 24 hours, call 1199.` },
      { q: `How do I enable bill notification alerts in the SNGPL app for ${city.name}?`, a: `Open the app, go to Settings → Notifications, and enable "New Bill Alert" and "Due Date Reminder." Ensure your phone has not blocked notifications for the SNGPL app in Android or iOS system settings.` },
      { q: `Can I pay the SNGPL bill directly inside the app?`, a: `The SNGPL Consumer App currently shows bill details and provides a payment redirect but does not process payments natively. Use Easypaisa, JazzCash, or your bank's app — copy your consumer number from the SNGPL app and paste it into the payment app for accuracy.` },
      { q: `What should I do if the SNGPL app registration OTP does not arrive for my ${city.name} number?`, a: `Ensure the mobile number registered with SNGPL matches the one you are using. If it does not match, visit ${city.office} to update the registered mobile number before attempting app registration. Alternatively, call 1199 and request an OTP resend.` },
    ],
    messaging: [
      { q: `Is the SNGPL WhatsApp bill service available 24 hours a day?`, a: `Yes. The SNGPL WhatsApp bill inquiry service runs 24/7 through an automated bot. Response time is typically under 30 seconds. Human support is not available via WhatsApp — for account issues, call 1199.` },
      { q: `What if the SNGPL WhatsApp bot does not respond to my consumer number?`, a: `First, verify you are messaging the correct official SNGPL WhatsApp number from sngpl.com.pk. Second, ensure your consumer number is typed as digits only (no spaces, dashes, or letters). If the issue persists, the WhatsApp service may be temporarily down — use the portal instead.` },
      { q: `Can I get a PDF duplicate bill via WhatsApp for ${city.name}?`, a: `Yes. The SNGPL WhatsApp automated response includes a PDF download link for your current bill. Tap the link to open it in your browser, then use your phone's share or download function to save the PDF.` },
      { q: `Does the SNGPL SMS service work on non-Telenor SIM cards in ${city.name}?`, a: `SNGPL's SMS bill inquiry short code is accessible from all major Pakistani networks (Telenor, Jazz, Ufone, Zong). Standard SMS rates apply. The response is a plain-text message with the bill amount and due date.` },
      { q: `How do I know if the WhatsApp number I have is the real SNGPL number?`, a: `Always verify the WhatsApp number by cross-checking it on the official SNGPL website at sngpl.com.pk under the "Contact Us" or "Digital Services" section. Numbers shared on Facebook, Twitter, or WhatsApp groups may be fraudulent — do not send consumer details to unverified numbers.` },
      { q: `Can I request a bill for a specific previous month via SNGPL WhatsApp?`, a: `No. The SNGPL WhatsApp service only returns your most recently generated bill. For a bill from a specific prior month, use the SNGPL mobile app (12-month history) or visit ${city.office}.` },
    ],
    dispute: [
      { q: `What is the maximum time SNGPL has to resolve a billing dispute in ${city.name}?`, a: `SNGPL's internal service level target for billing disputes is 15 to 30 working days. Complex cases involving meter inspections or archive reviews may take longer. If your dispute is unresolved after 30 working days, escalate to OGRA's consumer complaint cell at ogra.org.pk.` },
      { q: `Should I pay a disputed SNGPL bill while the dispute is being processed?`, a: `Yes. Pay the undisputed portion of the bill to avoid disconnection and late surcharges. If the full amount is disputed, pay the amount shown on your previous bill as a safe estimate. Note "payment under protest" in any reference field. Withholding full payment during a dispute can lead to disconnection, which is harder to resolve than a billing dispute.` },
      { q: `What evidence should I prepare for a ${city.name} SNGPL billing dispute?`, a: `Gather: (1) a photograph of your gas meter displaying the current reading with the date visible, (2) the disputed bill (printed or PDF), (3) the last 3–6 months of bills showing your normal consumption range, (4) any SNGPL complaint reference numbers from previous calls to 1199, and (5) payment receipts for all recent bills.` },
      { q: `Can SNGPL add old arrears to my ${city.name} bill without warning?`, a: `SNGPL can add previously unbilled arrears if a billing error or under-reading is discovered during an audit. However, they are required to notify you. If arrears appear unexpectedly on your bill, call 1199 immediately and ask for the "arrears advice notice" that should have been sent before the addition. If no notice was issued, file a formal complaint.` },
      { q: `What happens to late surcharges if I win a billing dispute?`, a: `If SNGPL confirms a billing error in your favor, both the incorrect charge and any associated late surcharges are reversed. The credit appears on your next bill. Keep your dispute reference number and follow up if the credit does not appear within 45 days.` },
      { q: `Can I escalate my SNGPL billing dispute to OGRA if ${city.office} does not help?`, a: `Yes. OGRA (Oil and Gas Regulatory Authority) accepts consumer complaints against SNGPL at ogra.org.pk or by calling OGRA's consumer helpdesk. File a complaint in writing with your SNGPL complaint reference number, the disputed amount, and the resolution history. OGRA has authority to direct SNGPL to resolve valid complaints.` },
    ],
    residential: [
      { q: `What is the domestic gas slab tariff applicable to residential consumers in ${city.name}?`, a: `SNGPL domestic residential slab rates approved by OGRA: 0–100 HHM = Rs. 200 flat; 101–300 HHM = Rs. 130/HHM; 301–500 HHM = Rs. 150/HHM; 501–800 HHM = Rs. 170/HHM; 801–1,200 HHM = Rs. 200/HHM; above 1,200 HHM = Rs. 250/HHM. GIDC (10%) and GST (17%) are added on top of the gas amount.` },
      { q: `Is a domestic SNGPL connection in ${city.name} allowed to be used for a home business?`, a: `A domestic (residential) connection is only for household use — cooking, heating, and domestic water heating. Using a domestic connection for commercial purposes (e.g., a restaurant, bakery, or workshop) violates SNGPL's terms and may result in conversion to a commercial tariff with back-billing at commercial rates. Apply for a separate commercial connection if running a home business.` },
      { q: `How many gas appliances can one residential SNGPL connection in ${city.name} support?`, a: `A standard residential connection with a G4 or G6 meter can typically support a gas stove (2–4 burners), a geyser, and a room heater simultaneously. If you wish to add a gas-fired generator or industrial-scale appliances, contact ${city.office} to assess whether your connection capacity and meter size need upgrading.` },
      { q: `Can multiple families sharing one building in ${city.name} use a single SNGPL connection?`, a: `Technically, a single connection with a shared meter is possible in joint family setups, but it means all consumption is billed under one consumer number. SNGPL can install sub-meters for individual flats in multi-unit buildings — apply at ${city.office} for a sub-metering arrangement. Each sub-meter gets its own billing and consumer number.` },
      { q: `How does SNGPL determine if a residential consumer in ${city.name} is over-consuming?`, a: `SNGPL flags accounts showing sustained consumption above 1,200 HHM/month for domestic connections. Such accounts may be subject to a site inspection to verify the connection is used for residential purposes only and not for commercial heating or industrial use.` },
      { q: `What is the fixed charge on a residential SNGPL bill in ${city.name}?`, a: `The fixed monthly meter rent for a domestic gas connection is a small amount set by OGRA — typically Rs. 10–50 per month depending on meter size (G4 or G6). This charge appears on your bill as "Fixed Charges" or "Meter Rent" and is billed every month regardless of how much gas you consume.` },
    ],
    commercial: [
      { q: `What is the commercial gas tariff rate for SNGPL in ${city.name}?`, a: `Commercial/industrial SNGPL tariffs are set by OGRA and are higher than residential rates. Commercial consumers are not on the slab system — they pay a per-HHM rate determined by their category (commercial, industrial, CNG, etc.). Contact ${city.office} or visit sngpl.com.pk for the current approved commercial rate schedule, as it is subject to annual revision.` },
      { q: `Can a commercial SNGPL customer in ${city.name} request a meter audit?`, a: `Yes. Any commercial consumer can request a formal meter audit through selfservice.sngpl.com.pk or by calling 1199. During an audit, an SNGPL engineer verifies the meter's accuracy, seal integrity, and calibration. If a fault is found, the meter is replaced and the billing period is reviewed for adjustment.` },
      { q: `How are commercial SNGPL bills different from domestic bills in ${city.name}?`, a: `Commercial bills include a demand charge (capacity charge) in addition to consumption charges. The billing cycle may be monthly or bi-monthly depending on the size. Commercial accounts also have higher disconnection risk thresholds and require a larger security deposit than domestic connections.` },
      { q: `What is the process for a new commercial SNGPL connection in ${city.name}?`, a: `Submit an application at ${city.office} with: business registration documents, property ownership or lease agreement, site plan, load requirement form, and CNIC of the proprietor/authorized signatory. SNGPL conducts a site survey, calculates the connection cost, and issues a demand notice. Commercial connections typically take 45–120 days from application to commissioning.` },
      { q: `Can a commercial SNGPL connection in ${city.name} be transferred to a new business owner?`, a: `Yes. Both the outgoing and incoming business owners must appear at ${city.office} with their CNICs, the business transfer documentation (sale deed or partnership transfer), and the latest paid SNGPL bill. The consumer number remains the same; only the registered account holder name changes.` },
      { q: `What is the security deposit required for a commercial SNGPL connection in ${city.name}?`, a: `Security deposits for commercial connections are calculated based on estimated monthly consumption. The deposit is typically equal to 2–3 months of estimated bills. The exact amount is advised by ${city.office} after the load assessment. The deposit is refunded when the connection is permanently surrendered, after deducting any outstanding dues.` },
    ],
    meter: [
      { q: `How often does SNGPL read gas meters in ${city.name}?`, a: `SNGPL reads gas meters monthly in ${city.name}. The exact reading date depends on the meter reading circuit assigned to your area — it can fall anywhere from the 1st to the 28th of the month. Your billing cycle date is visible on your bill as the "Reading Date."` },
      { q: `What does an "E" reading mean on my ${city.name} SNGPL bill?`, a: `"E" stands for Estimated. SNGPL used a computer-generated estimate instead of an actual meter reading — typically because the meter reader could not access the meter that month. The estimated reading is based on your historical consumption pattern. An actual reading will be taken the following month and any over- or under-estimation is corrected.` },
      { q: `How do I submit my own meter reading to SNGPL from ${city.name}?`, a: `Open the SNGPL Consumer App, navigate to "Meter Reading" or "Self-Meter Reading," enter the current reading visible on your meter display, and submit. This self-reading overrides the estimate if SNGPL cannot physically access your meter. Submit before the cutoff date printed on your bill or displayed in the app.` },
      { q: `What should I do if my ${city.name} gas meter is running fast (high readings)?`, a: `First, turn off all gas appliances and check if the meter dial is still moving — a moving dial with all appliances off indicates an internal gas leak or meter fault. Call 1199 emergency immediately for a gas leak. If there is no leak and you believe the meter is faulty, request a "Meter Inspection" via selfservice.sngpl.com.pk or 1199. The meter will be tested; if faulty, it is replaced and billing is recalculated.` },
      { q: `How long does it take for SNGPL to replace a faulty meter in ${city.name}?`, a: `After a meter inspection confirms a fault, SNGPL schedules replacement within 3–7 working days for standard residential meters in ${city.name}. If the meter needs to be procured (non-standard size), it may take up to 14 working days. You receive a complaint tracking number to follow up via 1199 or the self-service portal.` },
      { q: `What is the difference between a gas meter reading and a gas meter number?`, a: `The gas meter number (serial number) is stamped on the physical meter body and identifies the hardware device. The consumer number is your billing account identifier. When reporting a meter issue to SNGPL, provide both — the meter number helps the field team locate the physical device, while the consumer number links the case to your billing account.` },
    ],
    download: [
      { q: `Can I use a downloaded SNGPL PDF bill as address proof for a bank account in ${city.name}?`, a: `Yes. All major Pakistani banks — HBL, UBL, MCB, Meezan, Bank Alfalah, Allied Bank — accept a PDF duplicate bill downloaded from the SNGPL portal as valid utility bill address proof for KYC, account opening, and credit card applications. Print on plain paper if a physical copy is needed.` },
      { q: `How do I download an SNGPL bill for a previous month, not the current bill?`, a: `The SNGPL web portal only shows the current bill. For previous months, use the SNGPL mobile app — under "Bill History," bills for the last 12 months are available as downloadable PDFs. For bills older than 12 months, visit ${city.office} with your CNIC and consumer number to request an archive copy.` },
      { q: `Why does the SNGPL portal not show a download button for my ${city.name} bill?`, a: `This is usually a browser compatibility issue. Try using Google Chrome or Microsoft Edge in a standard (non-incognito) window. Disable any PDF-blocking browser extensions. On mobile, try the desktop version of the site by enabling "Desktop Mode" in your browser menu.` },
      { q: `Is the downloaded SNGPL bill valid for payment at a bank branch?`, a: `Yes. A printed PDF of your SNGPL bill is accepted at all bank branches for over-the-counter utility payments. The bank teller needs your consumer number (printed on the bill) and the payment amount — both are visible on the PDF. No stamp or certification is needed for branch payment purposes.` },
      { q: `How many times can I download my SNGPL ${city.name} bill from the portal?`, a: `There is no limit. The SNGPL portal generates the PDF on demand each time you request it. You can download it as many times as needed — for payments, address proof submissions, personal records, or sharing with family members.` },
      { q: `What file format is the SNGPL bill download and how large is it?`, a: `The SNGPL portal generates the bill as a PDF file, typically 200–500 KB in size. It is compatible with Adobe Acrobat Reader, Google Chrome's built-in PDF viewer, Apple Preview, and any other standard PDF application on Windows, Android, iOS, or macOS.` },
    ],
    history: [
      { q: `How many months of SNGPL bill history can I access online for ${city.name}?`, a: `The SNGPL mobile app stores 12 months of bill history as downloadable PDFs. The web portal only shows the current bill. For bills older than 12 months, submit an archive request at ${city.office} with your CNIC and consumer number.` },
      { q: `Can I compare my ${city.name} SNGPL bills year-over-year through the app?`, a: `The SNGPL app provides 12 months of history, which allows month-to-month comparison. For a year-over-year comparison (e.g., this November vs. last November), you will need to have downloaded and saved bills from the previous year, as the app does not archive beyond 12 months.` },
      { q: `Are historical SNGPL bills useful for income tax filing in Pakistan?`, a: `Yes. FBR (Federal Board of Revenue) accepts utility bills as supporting evidence for declared address and utility expense deductions. Your SNGPL bill history from the app covering January–December of the relevant tax year is sufficient for annual return filing.` },
      { q: `Can I get a certified stamp on a historical ${city.name} SNGPL bill for court use?`, a: `Yes. Visit ${city.office} and request a certified stamped copy of the specific billing month. For months within the last 12 months, the copy is available within 30 minutes. For older bills, submit a written archive request; turnaround is typically 3–5 working days.` },
      { q: `What is the best way to archive SNGPL bills long-term for ${city.name} consumers?`, a: `Download each bill immediately after generation using the SNGPL app push notification as a trigger. Save PDFs with a naming convention like SNGPL_[ConsumerNo]_YYYY_MM.pdf and store in a cloud folder (Google Drive, iCloud, Dropbox). This ensures access even if your phone is lost and protects against SNGPL's own archive limitations beyond 12 months.` },
      { q: `My SNGPL app shows blank history after reinstalling — how do I recover the bills?`, a: `Re-registration with the same consumer number after reinstalling recreates your account and reloads the available 12-month history from SNGPL's servers — you do not lose any bills stored server-side. Previously downloaded PDFs saved to your phone may be in your device's "Downloads" folder. Check both "Downloads" and any cloud backup linked to your previous phone.` },
    ],
    month: [
      { q: `Why are SNGPL gas bills in ${city.name} higher in winter months?`, a: `Winter months (November through February) see dramatically higher gas consumption in ${city.name} because domestic gas heaters, floor heaters, and geysers are used continuously. Households move from Slab 2–3 (summer cooking use) into Slab 4–5 (heavy winter heating), which have higher per-HHM rates, compounding the impact of higher consumption.` },
      { q: `When exactly does SNGPL generate the monthly bill for ${city.name} consumers?`, a: `Bill generation in ${city.name} happens 2–3 working days after your meter reading date. Meter reading dates vary by area circuit — check the "Reading Date" field on your previous bill to identify your specific cycle. Bills are then available on the portal and app immediately after generation.` },
      { q: `How far in advance can I see my SNGPL monthly bill on the portal?`, a: `The bill becomes visible on billchecker.sngpl.com.pk as soon as it is generated — typically 8–15 days before the due date. Enable push notifications on the SNGPL app to be alerted the exact moment each month's bill is ready, so you can plan payment well before the due date.` },
      { q: `Can I request an early bill generation from SNGPL for my ${city.name} account?`, a: `No. Bill generation is tied to the meter reading cycle, which is controlled by SNGPL's field operations. Consumers cannot request early bill generation. If you need to know the approximate amount before the bill is generated, use the SNGPL bill calculator at /calculator to estimate based on your current meter reading.` },
      { q: `What is the typical SNGPL bill amount for a ${city.name} household in the hottest summer month?`, a: `In peak summer (June–July), a typical ${city.name} household using gas only for cooking and a geyser consumes 80–150 HHM per month, resulting in a bill of approximately Rs. 200–700 before taxes. Households that reduce geyser use in summer may be charged only the minimum fixed charge.` },
      { q: `Does SNGPL offer any winter bill discount or subsidy for low-income consumers in ${city.name}?`, a: `SNGPL does not currently offer a blanket winter discount. However, the Ehsaas Utility Stores and government subsidy programs announced by the federal government may include gas subsidy components for registered beneficiaries. Monitor the official SNGPL website and Pakistan government announcements for any active subsidy schemes available to ${city.name} consumers.` },
    ],
    default: [
      { q: `How quickly does the SNGPL bill portal load for ${city.name} consumers?`, a: `The official portal at billchecker.sngpl.com.pk typically loads your bill within 3–5 seconds on a standard broadband or 4G connection. During peak traffic periods (around bill generation dates), it may be slower. The SNGPL mobile app usually has faster individual account query response times.` },
      { q: `Is there a limit to how many times I can check my SNGPL bill online?`, a: `No. You can check your SNGPL bill as many times as you like — there is no rate limit on the portal or app. Many consumers in ${city.name} check weekly to monitor whether a new bill has been generated.` },
      { q: `Can I check an SNGPL bill without the consumer number using my CNIC?`, a: `The standard SNGPL portal requires a consumer number. However, if you call 1199 and provide your CNIC and full address, an agent can look up your consumer number and provide bill information. The self-service portal (selfservice.sngpl.com.pk) allows CNIC-based lookups after account registration.` },
      { q: `Does checking my SNGPL bill online affect my meter reading in ${city.name}?`, a: `No. Checking your bill online is a read-only operation — it does not interact with your meter or billing cycle in any way. It simply retrieves the current bill data from SNGPL's system.` },
      { q: `What browser works best for the SNGPL bill portal?`, a: `Google Chrome and Microsoft Edge provide the most reliable experience on the SNGPL bill portal. Firefox and Safari also work. Avoid very old browser versions or Internet Explorer. If the PDF download button does not appear, switch to Chrome.` },
      { q: `Is my SNGPL consumer data safe when I use the bill portal from ${city.name}?`, a: `The SNGPL portal uses HTTPS encryption. The only data you submit is your consumer number — no personal financial data, CNIC, or password is required. Third-party bill assistance sites (including this one) only redirect you to the official SNGPL portal and do not store your consumer number.` },
    ],
  };
  return map[bucket] ?? map.default;
}

// ─────────────────────────────────────────────────────────────────
// CONSUMER-NUMBER FAQs
// ─────────────────────────────────────────────────────────────────
function consumerNumberFaqs(type: string, city: CityData): FaqItem[] {
  const buckets: BucketDef[] = [
    { key: 'format',   matches: ['format', 'structure', 'digits', 'number-format'] },
    { key: 'recover',  matches: ['lost', 'recover', 'recovery', 'find'] },
    { key: 'digital',  matches: ['app', 'online', 'sms', 'whatsapp', 'lookup'] },
    { key: 'transfer', matches: ['transfer', 'change', 'update', 'new-connection', 'registration'] },
    { key: 'verify',   matches: ['verify', 'check', 'status', 'account', 'id', 'billing-account'] },
  ];
  const bucket = classify(type, buckets);
  const map: Record<string, FaqItem[]> = {
    format: [
      { q: `Are SNGPL consumer numbers unique across all cities or only within ${city.name}?`, a: `SNGPL consumer numbers are globally unique across the entire SNGPL network — no two accounts in any city share the same consumer number. This uniqueness is what makes the number a reliable payment identifier at all digital payment channels across Pakistan.` },
      { q: `Do SNGPL consumer numbers in ${city.name} ever change?`, a: `Your consumer number stays the same for the lifetime of the gas connection at that address, regardless of ownership changes, meter replacements, or tariff category changes. A new consumer number is only issued when a brand-new connection is established or when a connection is permanently surrendered and a new application is submitted.` },
      { q: `Why does my ${city.name} SNGPL consumer number start with a different prefix than my neighbor's?`, a: `Consumer numbers encode the distribution circle and zone. If you and your neighbor are on different meter reading circuits or were connected in different years, your prefixes may differ. Both numbers are equally valid — the prefix difference does not affect billing, payments, or complaint filing.` },
      { q: `What happens if I enter the wrong number of digits when paying SNGPL online?`, a: `The payment system will either return an error (if the number format is invalid) or apply the payment to a different consumer's account (if the entered number happens to match another valid account). Always verify the amount shown matches your bill amount before confirming payment — a mismatch is your clearest indicator of a wrong consumer number.` },
      { q: `Is the SNGPL consumer number printed on the gas meter itself?`, a: `No. The number on the meter is the meter serial number, not the consumer number. Your consumer number is printed on your SNGPL gas bills and on the connection card issued at the time of installation. To find it without a bill, use one of the five recovery methods: Easypaisa history, SNGPL app, calling 1199, self-service portal, or visiting ${city.office}.` },
      { q: `Can two different SNGPL connections at the same ${city.name} address have different consumer numbers?`, a: `Yes. If a property has more than one gas meter (e.g., a house with a separate meter for an annexe or rental unit), each meter has its own distinct consumer number. They appear as separate accounts in SNGPL's system and generate separate monthly bills.` },
    ],
    recover: [
      { q: `Can I recover my SNGPL consumer number using just my CNIC in ${city.name}?`, a: `Yes. Call 1199 and provide your CNIC and address. The agent will verify your identity and provide your consumer number. Alternatively, log into selfservice.sngpl.com.pk using your CNIC to view all linked consumer numbers.` },
      { q: `How do I find my SNGPL consumer number if I am a new tenant in ${city.name}?`, a: `Ask your landlord — the consumer number is in the landlord's name and on any previous bills they have. Alternatively, look at the meter card (a small card usually stored near the meter). As a last resort, check any Easypaisa or JazzCash payment history if the landlord or previous tenant paid bills using those apps.` },
      { q: `I moved to ${city.name} and there are no old bills — how do I get the consumer number?`, a: `Visit ${city.office} with your CNIC and proof of address (tenancy agreement, property documents). Counter staff can search by address to retrieve the consumer number associated with that property. This also lets you check whether any arrears exist before you take occupancy.` },
      { q: `Does the SNGPL self-service portal require registration to look up a consumer number?`, a: `Yes. selfservice.sngpl.com.pk requires a one-time account registration with your CNIC and a mobile number. After registration, the portal shows all consumer numbers linked to your CNIC in SNGPL's database. This is particularly useful if you own multiple gas connections in ${city.name} or elsewhere.` },
      { q: `How long does it take to get a consumer number from SNGPL helpline 1199?`, a: `If your CNIC is registered with SNGPL (it is, for anyone who applied for a connection), the 1199 agent can retrieve and provide your consumer number within 2–3 minutes of identity verification. Have your CNIC number and property address ready before calling.` },
      { q: `Can my landlord refuse to give me the SNGPL consumer number for my rented property in ${city.name}?`, a: `As a tenant, you need the consumer number to check bills and make payments. While the account is in the landlord's name, withholding the consumer number is not a standard SNGPL policy. If your landlord refuses, call 1199 with your address and a copy of your tenancy agreement — the agent can confirm the consumer number for the address.` },
    ],
    digital: [
      { q: `Can I manage multiple SNGPL consumer numbers in ${city.name} through one online account?`, a: `Yes. The SNGPL self-service portal (selfservice.sngpl.com.pk) and the SNGPL Consumer App both support multiple consumer numbers linked to a single registered account — up to five connections. This is ideal for property owners managing separate connections across ${city.areas} or other localities.` },
      { q: `Is SNGPL's online self-service portal secure for ${city.name} consumers?`, a: `Yes. selfservice.sngpl.com.pk uses HTTPS and requires CNIC-verified account registration. Do not use the same password as your email or banking apps. Enable two-factor authentication if available. Log out after each session, especially on shared or public devices.` },
      { q: `What service requests can I submit online without visiting ${city.office}?`, a: `Through selfservice.sngpl.com.pk you can: file billing complaints, request meter inspections, update your registered mobile number and email, track complaint status, and download bills. You still need to visit the office for new connection applications, connection transfers, and certified bill copies.` },
      { q: `How do I update my mobile number in the SNGPL system from ${city.name}?`, a: `Log into selfservice.sngpl.com.pk, navigate to "Account Settings" or "Profile Update," and submit a mobile number change request. You may need to verify with your CNIC. Alternatively, visit ${city.office} in person with your CNIC for an immediate update. The registered mobile number is used for OTPs and bill notifications, so keeping it current is important.` },
      { q: `Does SNGPL send email bill notifications to ${city.name} consumers?`, a: `SNGPL primarily uses SMS and app push notifications. Email notifications may be available if you register your email on selfservice.sngpl.com.pk, but this feature's availability depends on your account type. The most reliable digital alert system is the SNGPL app's push notification, which fires the moment your new bill is generated.` },
      { q: `Can I view my SNGPL account status online without calling 1199?`, a: `Yes. Enter your consumer number on billchecker.sngpl.com.pk — if a bill appears, your connection is active. On selfservice.sngpl.com.pk, your account status (active, suspended, disconnected) is visible under "My Account." A "no results" on the portal may indicate the account is pending or the consumer number is incorrect.` },
    ],
    transfer: [
      { q: `Can a tenant transfer an SNGPL connection from the landlord's name to their own in ${city.name}?`, a: `A tenant cannot unilaterally transfer the connection — the registered account holder (landlord) must consent and participate in the transfer process at ${city.office}. Both parties must appear with their CNICs and supporting documents. If a landlord is unreachable, SNGPL requires a court order or succession certificate for contested transfers.` },
      { q: `What is the fee for transferring an SNGPL connection in ${city.name}?`, a: `SNGPL may charge a nominal transfer processing fee, which varies and is confirmed at ${city.office} at the time of application. There is no publicly listed fixed fee — contact the office or call 1199 for the current amount. Any outstanding dues on the account must also be cleared before the transfer is processed.` },
      { q: `How long does a name transfer on an SNGPL connection in ${city.name} take?`, a: `A straightforward transfer (both parties present, all documents in order, no outstanding dues) typically takes 2–4 weeks. Complex cases involving estate settlements, court orders, or missing documentation can take several months.` },
      { q: `Does an SNGPL connection transfer in ${city.name} affect the security deposit?`, a: `The security deposit held by SNGPL is tied to the connection. When the account is transferred to a new holder, the new holder may be required to pay a fresh security deposit, and the original deposit is refunded to the previous holder after dues are cleared. Confirm the deposit arrangement with ${city.office} at the time of application.` },
      { q: `What happens to the SNGPL consumer number during a connection transfer?`, a: `The consumer number does not change. Only the registered account holder name and CNIC on file are updated. All billing history under the old account holder is archived, and new bills are generated under the new holder's name from the transfer date forward.` },
      { q: `Can I apply for a new SNGPL connection in ${city.name} if an old disconnected connection already exists at my address?`, a: `If the previous connection was permanently surrendered (meter removed, account closed), you apply for a new connection through the standard process. If the previous connection was only temporarily disconnected (meter still on-site, account active with arrears), you must first clear the arrears and apply for reconnection rather than a new connection.` },
    ],
    verify: [
      { q: `How do I verify that an SNGPL consumer number given to me for ${city.name} is real?`, a: `Enter the consumer number at billchecker.sngpl.com.pk. If a bill appears with the correct address, the number is real and active. If it returns no result or an address that does not match, do not make any payment using that number until the discrepancy is resolved with 1199.` },
      { q: `What does "Account Suspended" mean when I check an SNGPL consumer number?`, a: `A suspended SNGPL account indicates a temporary hold placed by SNGPL, usually pending a safety inspection, disputed billing investigation, or compliance review. Gas supply may or may not be interrupted. Contact 1199 with your consumer number to understand the specific reason and the steps required to restore normal account status.` },
      { q: `Can I check if my ${city.name} SNGPL account has any pending complaints using my consumer number?`, a: `Log into selfservice.sngpl.com.pk with your consumer number and CNIC. Under "My Complaints" or "Complaint Status," you can view all open and closed complaints, their current status, and the assigned tracking number. You can also check complaint status by calling 1199 with your complaint reference number.` },
      { q: `How do I confirm that my SNGPL payment was applied to the correct consumer account?`, a: `After your payment reflects (24–48 hours), enter your consumer number on the portal. The outstanding balance should drop to zero or to the remaining balance if partial payment was made. If the balance has not changed after 72 hours, your payment may have been applied to a different consumer number — call your payment channel first, then 1199.` },
      { q: `Is there a way to check the SNGPL account holder name for a consumer number in ${city.name}?`, a: `When you check a consumer number on the portal, the account holder name is usually displayed on the bill alongside the address. This allows you to confirm the name matches the person you expect — useful for tenants verifying they have the right consumer number before making a payment.` },
      { q: `What is the SNGPL account status if a consumer number returns no bill on the portal?`, a: `No bill on the portal typically means: (1) the bill has not yet been generated this month (wait for the billing cycle date), (2) the consumer number is incorrect — recheck all digits, (3) the account has been permanently closed, or (4) a data synchronization issue on the portal — try again after 24 hours before calling 1199.` },
    ],
    default: [
      { q: `Where is the consumer number printed on an SNGPL ${city.name} gas bill?`, a: `Your SNGPL consumer number is printed in the header section of every gas bill, usually in a box labeled "Consumer No.," "Cust. No.," or "Account Number." It is typically one of the first pieces of information visible when you open the bill. On a bill PDF, it appears in the top-right or top-left portion of the document.` },
      { q: `Do I need a consumer number to pay an SNGPL bill at a bank in ${city.name}?`, a: `Yes. All payment channels — Easypaisa, JazzCash, bank ATMs, internet banking, and over-the-counter bank payments — require your SNGPL consumer number. It is the only identifier used to route your payment to the correct account. No other information (CNIC, meter number, address) is used as a payment identifier.` },
      { q: `Can two people share the same SNGPL consumer number in ${city.name}?`, a: `No. Each SNGPL consumer number is assigned to exactly one gas connection. However, multiple family members or tenants at the same address can all know the consumer number and use it to check bills or make payments, since the portal and payment channels are open (no password required).` },
      { q: `What is the consumer number format for industrial SNGPL connections in ${city.name}?`, a: `Industrial consumer numbers follow the same 10–13 digit structure as domestic numbers, but the regional and circle prefix codes differ to reflect the industrial supply zone. Industrial accounts are typically longer and may include a check digit. The exact format is confirmed by ${city.office} at the time of connection commissioning.` },
      { q: `How do I link my SNGPL consumer number to my email for digital bill delivery in ${city.name}?`, a: `Log into selfservice.sngpl.com.pk, navigate to "Account Settings" or "Notification Preferences," and add your email address. Select "Email" under bill notification preferences. The portal sends a verification link to your email. Once verified, digital bills will be emailed to your address monthly alongside the standard app notification.` },
      { q: `Is the SNGPL consumer number required to report a gas leak in ${city.name}?`, a: `No. For gas emergencies, call SNGPL's 24-hour emergency helpline 1199 immediately and give your address — your consumer number is not required for emergency dispatch. SNGPL sends a field team based on the address alone. Your consumer number is only needed for billing and service request follow-ups.` },
    ],
  };
  return map[bucket] ?? map.default;
}

// ─────────────────────────────────────────────────────────────────
// DUPLICATE-BILL FAQs
// ─────────────────────────────────────────────────────────────────
function duplicateBillFaqs(type: string, city: CityData): FaqItem[] {
  const buckets: BucketDef[] = [
    { key: 'portal',    matches: ['portal', 'online', 'desktop', 'digital', 'soft-copy', 'electronic', 'pdf-download', 'get-copy', 'download-via-portal'] },
    { key: 'app',       matches: ['app', 'android', 'iphone', 'mobile-download', 'save-to-phone'] },
    { key: 'messaging', matches: ['whatsapp', 'sms', 'download-via-whatsapp', 'download-via-sms'] },
    { key: 'office',    matches: ['office', 'visit', 'certified', 'photocopy'] },
    { key: 'legal',     matches: ['validity', 'valid', 'bank-payment', 'address-proof', 'proof', 'legal'] },
    { key: 'history',   matches: ['archive', 'history', 'old', 'previous', 'monthly-bill-copy', 'batch', 'email-bill'] },
  ];
  const bucket = classify(type, buckets);
  const map: Record<string, FaqItem[]> = {
    portal: [
      { q: `Does the SNGPL portal show the current bill only or all previous bills for ${city.name} consumers?`, a: `The SNGPL portal at billchecker.sngpl.com.pk shows only the most recently generated bill. For previous bills, use the SNGPL mobile app which provides 12 months of downloadable history.` },
      { q: `Can I download the SNGPL duplicate bill in any format other than PDF?`, a: `The portal generates a PDF. If you need another format (e.g., JPG image), open the PDF in Chrome, zoom in, and take a screenshot. Most institutional requirements — banks, NADRA, embassies — accept PDFs; image formats are generally not needed.` },
      { q: `Does downloading a duplicate SNGPL bill from the portal cost anything?`, a: `No. Downloading your bill from the official SNGPL portal is completely free. Standard data charges from your ISP or mobile carrier apply for the internet connection itself. No fees are charged by SNGPL for portal-based bill downloads.` },
      { q: `The SNGPL portal says my bill is not found — how do I fix this for a ${city.name} account?`, a: `Check three things: (1) ensure the consumer number is entered with all digits including leading zeros, (2) confirm the bill has been generated this month (check if the reading date has passed), (3) if neither resolves it, call 1199 to confirm your consumer number is correctly active in the system.` },
      { q: `Can I share the SNGPL portal link with my landlord in ${city.name} to let them download the bill?`, a: `Yes. Simply share the URL billchecker.sngpl.com.pk with your landlord or anyone who needs the bill. They enter the consumer number to download — no login or password is required. This is safe since the portal only displays billing information and does not allow account changes.` },
      { q: `How do I download an SNGPL duplicate bill on a slow mobile connection in ${city.name}?`, a: `The SNGPL portal is lightweight and works even on 2G or low-speed connections. If the PDF download is slow, try using the "Print to PDF" method via your browser — this loads the bill in HTML first (faster), then converts to PDF on your device without downloading a large file from the server.` },
    ],
    app: [
      { q: `Does the SNGPL app bill history survive if I uninstall and reinstall the app?`, a: `Yes. Your bill history is stored on SNGPL's servers, not on your device. After reinstalling the app and logging in with the same consumer number, your 12-month history reloads. Previously downloaded PDFs saved to your phone's storage may be in the Downloads folder.` },
      { q: `Why can I only see the last 12 months of bills in the SNGPL app, not older ones?`, a: `The SNGPL app is designed to show the most recent 12-month rolling history. Bills older than 12 months are archived in SNGPL's backend systems and are not accessible through the app's current interface. Request older bills from ${city.office}.` },
      { q: `Is the SNGPL app bill PDF the same quality as the portal PDF for ${city.name} consumers?`, a: `Yes. Both the app and portal generate the same PDF from the same SNGPL billing system. The formatting, content, and legal validity are identical. The app download is slightly more convenient as it does not require re-entering the consumer number.` },
      { q: `Can I print an SNGPL duplicate bill directly from the mobile app on a ${city.name} Wi-Fi printer?`, a: `Open the downloaded PDF from the SNGPL app using your phone's file manager or PDF viewer. Tap the share icon and select "Print." Your Android or iOS device's print menu will appear — select your Wi-Fi printer. The printed output is identical to a portal-downloaded and printed bill.` },
      { q: `What happens to SNGPL app bill notifications if I change my phone in ${city.name}?`, a: `App push notifications are device-specific. When you install the SNGPL app on a new phone and log in with your consumer number, push notifications are re-registered to the new device automatically. You will not miss notifications for bills generated after the new device registration.` },
      { q: `Does the SNGPL app work on tablets for ${city.name} consumers?`, a: `Yes. The SNGPL Consumer App is available on Android and iOS, which includes tablets (iPad and Android tablets). The interface may be phone-optimized and appear letterboxed on a tablet, but all functionality — including bill download — works on tablet devices.` },
    ],
    messaging: [
      { q: `Is the PDF received via SNGPL WhatsApp legally valid for bank submissions in ${city.name}?`, a: `Yes. The PDF delivered via SNGPL's official WhatsApp service is generated directly from SNGPL's billing database and is identical to a portal download. Banks in ${city.name} — HBL, MCB, UBL, Meezan — accept it for KYC and address verification purposes.` },
      { q: `Why did SNGPL WhatsApp send me a bill PDF link but it does not open?`, a: `The link is a temporary signed URL that expires after a few hours for security. If the link no longer opens, simply send your consumer number to the SNGPL WhatsApp number again to generate a fresh link. Use it immediately after receiving the message.` },
      { q: `Can I forward the SNGPL WhatsApp bill PDF to someone else in ${city.name}?`, a: `Yes. Once you download the PDF to your device, you can forward it via WhatsApp, email, or any other channel. The forwarded PDF retains full legal validity as it is an unmodified copy of the SNGPL-issued document.` },
      { q: `Does the SNGPL SMS service deliver a PDF bill or just text?`, a: `The SNGPL SMS service delivers a plain text response containing: account holder name, bill amount, due date, and billing period. It does not provide a PDF download link — that is only available through the portal, app, and WhatsApp channels. SMS is suitable for confirming the amount before payment.` },
      { q: `How do I save the WhatsApp SNGPL bill PDF to my Google Drive or iCloud from ${city.name}?`, a: `After the SNGPL WhatsApp bot sends the PDF link, open it in your browser. On Android, tap the share icon and select "Save to Drive." On iPhone, tap the share icon and select "Save to Files" (which includes iCloud Drive). The PDF is then accessible from any device linked to that cloud account.` },
      { q: `Can I request multiple months of bills via SNGPL WhatsApp at once?`, a: `No. The WhatsApp service only returns the current active bill each time you send your consumer number. It does not support historical bill requests. For multiple months, use the SNGPL app's bill history feature or visit ${city.office}.` },
    ],
    office: [
      { q: `What are the SNGPL office hours in ${city.name} for duplicate bill requests?`, a: `SNGPL offices in ${city.name} operate Monday to Friday, 9 AM to 5 PM. Saturday, Sunday, and public holidays are non-working days. The specific office address for ${city.name} is ${city.office}. Call 1199 to confirm if hours have changed before making a dedicated visit.` },
      { q: `Can a family member collect a certified SNGPL duplicate bill on my behalf in ${city.name}?`, a: `Yes. A family member can collect a certified bill on your behalf if they bring: your original CNIC copy, a written authorization letter signed by you (the account holder), and their own original CNIC. The SNGPL counter may require this authorization for certified copies but usually allows simple information requests for family members.` },
      { q: `How much does a certified SNGPL duplicate bill cost at ${city.office}?`, a: `SNGPL typically charges a nominal printing fee of Rs. 50–200 for counter-issued certified bills. This varies by office. For bills older than 12 months requiring archive retrieval, there may be an additional archive fee. Confirm the current fee by calling 1199 before visiting.` },
      { q: `What is the waiting time at ${city.office} for a duplicate bill?`, a: `During off-peak hours (Tuesday–Thursday, mid-morning), waiting time for a simple duplicate bill is typically 15–30 minutes. On Mondays or around bill due dates, queues are longer — 45 minutes to 2 hours. Arriving before 10 AM tends to minimize wait time.` },
      { q: `Can I get a certified SNGPL bill for a specific previous month at the ${city.name} office?`, a: `Yes. Specify the billing month when you arrive at the counter. For bills within the last 12 months, the staff can print and stamp the copy immediately. For bills older than 12 months, you must submit a written archive request — the retrieval takes 3–5 working days and you will be called when it is ready.` },
      { q: `What if ${city.office} is closed when I urgently need a duplicate bill?`, a: `For urgent situations when the office is closed, use the portal or app to download a digital PDF — this is accepted by all banks and most institutions. For court submissions requiring a physical stamp, you will need to wait for the office to reopen. The 1199 helpline (24/7) can advise on the nearest open SNGPL service center.` },
    ],
    legal: [
      { q: `Is a downloaded SNGPL PDF bill accepted as address proof by embassies for ${city.name} residents?`, a: `Most embassies accept utility bills as address proof. A PDF printed on plain paper is generally sufficient, but some embassies prefer the most recent bill (not older than 3 months) and may require a notary attestation. Check the specific embassy's requirements before submission — if in doubt, obtain a certified copy from ${city.office}.` },
      { q: `Can I use an SNGPL duplicate bill as proof of domicile for government applications in ${city.name}?`, a: `Yes. SNGPL gas bills are widely accepted as proof of residence for government applications including domicile certificates, CNIC address updates, and voter list registration. For these purposes, a PDF print is usually sufficient; the officer may request that you show the original-looking print on plain white paper with no handwritten alterations.` },
      { q: `Is a photocopy of an SNGPL bill valid for address proof in ${city.name}?`, a: `A photocopy of a physical bill is accepted for many informal purposes. For formal submissions to banks, NADRA, or government offices, the institution may require an original print (from the portal or app) rather than a photocopy of a postal bill. A fresh portal-generated PDF print is preferable and more reliably accepted than a photocopy.` },
      { q: `Does an SNGPL duplicate bill need a notary stamp to be legally valid in ${city.name}?`, a: `No notary stamp is required for payments, bank KYC, or most government submissions. Notary attestation is only needed for specific international submissions (some visa applications, foreign education applications) where the accepting authority explicitly requires it. In those cases, print the PDF and have a local notary attest the print.` },
      { q: `Can an SNGPL bill be used as address proof if the account is in my landlord's name in ${city.name}?`, a: `Banks and institutions typically require the utility bill to be in your name. A bill in your landlord's name alone is not accepted as your personal address proof. However, if paired with a tenancy agreement bearing your CNIC details and the property address, some institutions may accept the combination. Ask the specific institution for their policy.` },
      { q: `What is the legal validity period of an SNGPL duplicate bill downloaded today in ${city.name}?`, a: `For most purposes, a utility bill is valid for 3 months from its generation date. Banks typically require a bill not older than 3 months for KYC. Visa applications usually require a bill from the last 3–6 months. Since the portal only generates your current bill, a fresh download is always current. Check the bill's generation date — the month and year are printed prominently.` },
    ],
    history: [
      { q: `How do I download all 12 months of SNGPL bills at once for ${city.name}?`, a: `The SNGPL app does not offer a batch download. You must download each month individually from the "Bill History" tab. For a batch archive, consider using the Android screen automation approach: manually download each month, then bulk-save to your cloud storage. For bulk official copies, visit ${city.office} and request all months in a single written application.` },
      { q: `I need my SNGPL bills from 2 years ago for a property sale in ${city.name}. How do I get them?`, a: `Bills older than 12 months are not available through digital channels. Visit ${city.office} and submit a written application specifying the billing months needed. Include your consumer number, CNIC, and the reason (property transaction). The archive retrieval typically takes 3–5 working days. There may be a per-copy fee.` },
      { q: `Does SNGPL send bill PDFs by email automatically to ${city.name} consumers?`, a: `Email bill delivery is available through selfservice.sngpl.com.pk if you register and enable it in notification settings. It is not enabled by default. Most consumers receive bills by post (physical) or check the app and portal digitally. Enabling email notifications is highly recommended as a backup alongside app notifications.` },
      { q: `Can I get my SNGPL bill history for income tax purposes in ${city.name}?`, a: `Yes. Download the 12 months of bills from the SNGPL app — these are sufficient for FBR income tax return filings as utility expense documentation. If you need bills from a specific year older than 12 months, request certified copies from ${city.office} with written justification.` },
      { q: `If I change my phone, do I lose my SNGPL bill download history?`, a: `Downloaded PDF files saved to your phone's storage are device-specific and may not transfer automatically. Bills stored in your cloud backup (Google Drive, iCloud) will transfer. The SNGPL app's bill history is always retrievable from the server by logging in again — you only lose locally saved PDFs that were not backed up to the cloud.` },
      { q: `Can I request SNGPL to email me monthly bills automatically for my ${city.name} account?`, a: `Register on selfservice.sngpl.com.pk, add your email address under account settings, and enable "Email Bill Delivery." Alternatively, the most reliable method is the SNGPL app push notification — you receive an alert the moment your new bill is generated each month, prompting you to open and download it immediately.` },
    ],
    default: [
      { q: `What is a duplicate SNGPL bill and when do I need one?`, a: `A duplicate SNGPL bill is an exact reprint of your original gas bill. You need one when the original postal bill is lost, damaged, or delayed; for bank KYC address proof; for embassy visa applications; for income tax documentation; and for property transactions requiring proof of utility connection at an address.` },
      { q: `Is a duplicate SNGPL bill free or does it cost money in ${city.name}?`, a: `Duplicate bills downloaded from the official portal or app are completely free. Bills collected in person from ${city.office} may incur a small printing fee of Rs. 50–200 for counter service. There is no charge for viewing or downloading digitally.` },
      { q: `Can I get a duplicate SNGPL bill for a connection that is now disconnected in ${city.name}?`, a: `Yes, for up to 12 months after the last bill. For older disconnected accounts, visit ${city.office} with your CNIC and previous consumer number. SNGPL archives are maintained for several years. There may be a fee for certified copies of disconnected accounts.` },
      { q: `How quickly can I get a duplicate SNGPL bill in an emergency in ${city.name}?`, a: `Instantly — within 2 minutes online via billchecker.sngpl.com.pk or the SNGPL app. No appointment, no wait, no cost. For a certified physical copy, same-day service is available at ${city.office} during working hours for current-month bills.` },
      { q: `Does my duplicate SNGPL bill show the same consumer number as the original?`, a: `Yes. A duplicate bill is byte-for-byte identical to the original in terms of all account information including consumer number, meter number, name, address, consumption, charges, and due date. The word "Duplicate" may be watermarked on the printout, which does not affect its validity for any purpose.` },
      { q: `Can I use a duplicate SNGPL bill to pay at a JazzCash franchise in ${city.name}?`, a: `JazzCash franchise agents do not require the physical bill document at all — they only need your consumer number. Tell the agent your consumer number, confirm the amount displayed on their terminal, and pay cash. The physical or PDF bill is irrelevant for franchise-based payments.` },
    ],
  };
  return map[bucket] ?? map.default;
}

// ─────────────────────────────────────────────────────────────────
// PAYMENT FAQs
// ─────────────────────────────────────────────────────────────────
function paymentFaqs(type: string, city: CityData): FaqItem[] {
  const buckets: BucketDef[] = [
    { key: 'easypaisa', matches: ['easypaisa', 'mobile-payment'] },
    { key: 'jazzcash',  matches: ['jazzcash'] },
    { key: 'bank',      matches: ['hbl', 'ubl', 'mcb', 'meezan', 'allied', 'bank-transfer', 'atm', 'internet-banking', 'mobile-banking', 'bank-branch'] },
    { key: 'deadline',  matches: ['late-payment', 'deadline', 'due-date', 'before-due', 'avoid-disconnection', 'advance', 'partial'] },
    { key: 'receipt',   matches: ['receipt', 'confirmation', 'confirmation-check'] },
    { key: 'failure',   matches: ['failed', 'missing-payment', 'not-reflected', 'cash', 'franchise', 'over-counter'] },
  ];
  const bucket = classify(type, buckets);
  const map: Record<string, FaqItem[]> = {
    easypaisa: [
      { q: `Does Easypaisa charge a fee for SNGPL gas bill payment in ${city.name}?`, a: `Yes. Easypaisa charges a convenience fee of Rs. 10–25 per transaction depending on the bill amount tier. This fee is charged on top of your bill amount. The fee is displayed on screen before you confirm payment — always check the total amount before authorizing.` },
      { q: `Can I pay an SNGPL bill via Easypaisa without a smartphone in ${city.name}?`, a: `Yes. Dial *786# on any Telenor SIM (or partner networks) — this USSD service works on basic feature phones without a smartphone or internet connection. Navigate the menu to Bill Payments → Utilities → Gas → SNGPL → enter consumer number → confirm amount → enter PIN.` },
      { q: `How long does Easypaisa take to process an SNGPL payment for ${city.name} accounts?`, a: `Easypaisa processes the payment instantly from your wallet, but SNGPL typically reflects it in their system within 24–48 hours. The portal may still show the outstanding balance during this window — check again after 48–72 hours before escalating to 1199.` },
      { q: `What is the maximum SNGPL bill amount I can pay through Easypaisa in one transaction?`, a: `Easypaisa has a per-transaction limit for utility bill payments — currently up to Rs. 50,000. Commercial SNGPL bills exceeding this amount require splitting into multiple transactions or using a bank transfer channel. Check Easypaisa's current limits as they are updated periodically.` },
      { q: `Can I save my SNGPL consumer number in Easypaisa to avoid re-entering it every month in ${city.name}?`, a: `Yes. After your first SNGPL payment, the Easypaisa app offers to save the biller under "Saved Billers" or "Favorites." Save it with a recognizable label. Next month, select it from Saved Billers, confirm the fetched amount, and pay with one tap — much faster than re-entering the consumer number.` },
      { q: `Is it safe to pay SNGPL bills through the Easypaisa app from ${city.name}?`, a: `Yes, if you use the official Easypaisa app downloaded from Google Play Store or Apple App Store. Ensure you see the "SNGPL" listing under official utility providers. Never enter your consumer number or make payments through unverified third-party apps or websites that claim to use Easypaisa's API.` },
    ],
    jazzcash: [
      { q: `Does JazzCash auto-payment for SNGPL actually work reliably for ${city.name} consumers?`, a: `JazzCash's auto-payment (scheduled payment) feature attempts payment on the date you set. Ensure your JazzCash wallet or linked bank account has sufficient funds on that date. If the balance is insufficient, the auto-payment fails silently — always check your payment history around the scheduled date to confirm it processed.` },
      { q: `What is the JazzCash USSD code for SNGPL bill payment from ${city.name}?`, a: `Dial *786# on a Jazz or Warid SIM. Navigate: Bill Payments → Gas → SNGPL → enter consumer number → amount is displayed → enter MPIN to confirm. This works without internet on any phone.` },
      { q: `Can I pay SNGPL from a JazzCash wallet that has insufficient balance in ${city.name}?`, a: `No. JazzCash requires sufficient balance in the wallet or the linked bank account at the time of payment. If your wallet balance is below the bill amount, you must top up first (via bank transfer, Easypaisa exchange, or JazzCash agent) before making the SNGPL payment.` },
      { q: `How do I view my JazzCash SNGPL payment history for ${city.name}?`, a: `Open the JazzCash app and go to "Transaction History" or "Payment History." Filter by "Bill Payments" or search for "SNGPL" to view all past gas bill payments. Each transaction shows the date, amount, consumer number, and transaction ID — save these screenshots monthly for your records.` },
      { q: `Does JazzCash charge more for SNGPL payments than Easypaisa in ${city.name}?`, a: `JazzCash and Easypaisa charge broadly similar convenience fees for SNGPL utility payments — typically Rs. 10–25. Exact amounts vary slightly and can change. Check the fee displayed on the confirmation screen before authorizing. For very large commercial bills, consider bank internet banking which may have zero additional fees.` },
      { q: `Can I pay someone else's SNGPL bill using my JazzCash account in ${city.name}?`, a: `Yes. JazzCash does not restrict who the payer is — any JazzCash account holder can pay any SNGPL consumer number. Simply enter the other consumer's number, confirm the displayed amount matches their bill, and authorize payment from your wallet. This is commonly used by family members or landlords paying bills on behalf of others.` },
    ],
    bank: [
      { q: `Which banks support SNGPL bill payment at ATMs in ${city.name}?`, a: `All banks on the 1-Link network support SNGPL bill payment at ATMs — this includes HBL, UBL, MCB, Allied Bank, Meezan Bank, Bank Alfalah, NBP, Habib Metropolitan, Askari Bank, and most other scheduled banks. Look for "Utility Bill Payment" or "Other Services" in the ATM menu.` },
      { q: `How do I pay my SNGPL bill via HBL internet banking from ${city.name}?`, a: `Log into HBL's internet banking portal. Navigate to "Payments" → "Utility Payments" → "Gas." Select SNGPL as the provider. Enter your consumer number, confirm the fetched amount, and authenticate with your HBL OTP. Payment reflects in SNGPL's system within 24–48 hours.` },
      { q: `Is there a transaction fee for paying SNGPL at a bank ATM in ${city.name}?`, a: `Paying at your own bank's ATM is typically free for account holders. Paying at another bank's ATM may incur an interbank fee of Rs. 20–50. Over-the-counter bank branch payments may include a service charge of Rs. 10–30. Internet and mobile banking payments are usually free.` },
      { q: `Can I pay an SNGPL commercial bill above Rs. 100,000 through bank internet banking in ${city.name}?`, a: `Yes. Bank internet banking supports high-value utility payments. Check your daily transaction limit — many banks have a default limit of Rs. 500,000 per day for internet banking transfers, which is sufficient for most commercial gas bills. Call your bank to increase the limit temporarily if needed for very large bills.` },
      { q: `What do I do if my bank shows an error when trying to pay SNGPL in ${city.name}?`, a: `First check that your consumer number is correct. Bank systems sometimes show "biller not found" if your SNGPL account is temporarily inactive or the bill has not yet been generated. If the error persists, try an alternative bank or use Easypaisa/JazzCash as a backup. Contact your bank's customer service with the exact error message for account-specific issues.` },
      { q: `Can I pay SNGPL at any 1-Link ATM without my bank card in ${city.name}?`, a: `Some 1-Link ATMs support "CNIC-based utility payment" which does not require a bank card — you use your CNIC and biometric fingerprint. This is designed for unbanked consumers. Look for this option on ATMs labeled with the 1-Link or BISP payment logos.` },
    ],
    deadline: [
      { q: `Is there a grace period after the SNGPL due date in ${city.name} before the surcharge applies?`, a: `No. SNGPL does not provide a grace period. The 10% late surcharge is applied automatically the day after the due date. There is no appeal process for a surcharge that has already been applied. Always pay at least 3 days before the due date to account for payment processing time.` },
      { q: `Can I pay my SNGPL ${city.name} bill in installments if I cannot afford the full amount?`, a: `SNGPL does not officially offer installment plans for standard bills. However, if you have large accumulated arrears, calling 1199 or visiting ${city.office} to request an informal payment arrangement is worth attempting — particularly for long-standing consumers with a good payment history. Any arrangement must be confirmed in writing.` },
      { q: `What time on the due date does the SNGPL late surcharge get applied in ${city.name}?`, a: `SNGPL's batch processing typically runs at midnight on the due date. Payments made and reflecting before midnight are considered on-time. Payments made on the due date that take more than a few hours to process risk being batch-processed on the next day. To be completely safe, pay 3 days in advance.` },
      { q: `If I pay my SNGPL bill before the due date but the amount is wrong, what happens in ${city.name}?`, a: `If you pay less than the full amount, the difference carries forward as arrears on your next bill — subject to the 10% surcharge on the unpaid portion. If you overpay, the excess appears as a credit on your next bill. Always confirm the exact amount before paying using the portal or app.` },
      { q: `Can I get a due date extension from SNGPL in ${city.name} without visiting the office?`, a: `Call 1199 before the due date. Extensions can sometimes be granted over the phone for consumers with a clean payment record. The agent will note the extension on your account. However, extensions are not guaranteed and should not be counted on as a regular strategy — pay on time whenever possible.` },
      { q: `What is advance bill payment for SNGPL and how does it work in ${city.name}?`, a: `You can deposit an advance payment into your SNGPL account through selfservice.sngpl.com.pk or at ${city.office}. The advance balance is held as a credit and automatically deducted from future bills as they are generated. This is particularly useful for ${city.name} consumers who want to pre-pay winter bills in advance during summer when cash flow is easier.` },
    ],
    receipt: [
      { q: `How do I get a duplicate receipt if I lost my SNGPL payment proof in ${city.name}?`, a: `For Easypaisa: open the app → Transaction History → find the SNGPL payment → screenshot or download the transaction detail. For JazzCash: same process under Payment History. For bank payments: log into your bank app → Statements/Transaction History → find and download the SNGPL payment entry. ATM receipts cannot be reprinted — contact your bank for a transaction certificate.` },
      { q: `How long should I keep SNGPL payment receipts in ${city.name}?`, a: `Keep payment receipts for at least 3 months — long enough to confirm the payment has fully processed and been reflected in SNGPL's system. For the year-end bill (December), keep the receipt until your SNGPL account statement confirms the balance is zero. For property transactions, keep receipts for the full duration of your tenancy or ownership.` },
      { q: `Does SNGPL send a payment confirmation SMS after I pay my bill in ${city.name}?`, a: `SNGPL itself does not typically send a payment confirmation SMS. The confirmation comes from your payment channel — Easypaisa or JazzCash sends an immediate SMS receipt. Bank payments generate an in-app notification or email depending on your bank's settings. If you want SNGPL-side confirmation, check the portal 24–48 hours later for the outstanding balance to drop to zero.` },
      { q: `Is a screenshot of a JazzCash payment screen accepted as proof by SNGPL in ${city.name}?`, a: `Yes. When you contact SNGPL 1199 about a payment not reflecting, a JazzCash or Easypaisa payment confirmation screenshot showing the transaction ID, date, consumer number, and amount is accepted as prima facie evidence. The agent will trace the payment batch using the transaction ID.` },
      { q: `What information must a valid SNGPL payment receipt contain in ${city.name}?`, a: `A valid payment receipt must show: (1) the payment channel name (Easypaisa, JazzCash, or bank name), (2) transaction ID or reference number, (3) date and time of payment, (4) amount paid, (5) the biller identified as SNGPL, and (6) the consumer number the payment was made against. All six are present in Easypaisa and JazzCash app receipt screens.` },
      { q: `Can I submit an SNGPL payment receipt to my landlord as proof I paid the gas bill in ${city.name}?`, a: `Yes. A payment receipt from Easypaisa, JazzCash, or bank statement showing your SNGPL consumer number and payment amount is standard proof for landlord-tenant purposes. For extra clarity, also show the bill portal confirming zero balance after your payment.` },
    ],
    failure: [
      { q: `My SNGPL payment went through on Easypaisa but the portal still shows outstanding. What should I do in ${city.name}?`, a: `Wait 72 hours first — SNGPL processes batch payments and delays are common near due dates. If the balance has not updated after 72 hours, call Easypaisa (042-111-003-737) to confirm dispatch, then call SNGPL 1199 with your Easypaisa transaction ID, date, amount, and consumer number for manual matching.` },
      { q: `I accidentally paid the wrong SNGPL consumer number. Can it be reversed in ${city.name}?`, a: `Contact SNGPL 1199 immediately and your payment channel (Easypaisa/JazzCash/bank). Provide both the consumer number you intended to pay and the one you accidentally paid. SNGPL can request an inter-account transfer, but this process takes 2–4 weeks and is not guaranteed. Future disconnection of your actual account due to non-payment cannot be waived during this period — pay the correct account again and resolve the misdirected payment as a separate issue.` },
      { q: `Can an SNGPL franchise payment in ${city.name} fail or be lost?`, a: `Franchise payments are processed in real-time at the point of sale. If the franchise agent confirms payment and gives you a receipt, the payment should reflect in SNGPL's system within 24 hours. If it does not, return to the franchise with your receipt — they have a transaction record and can contact their clearing bank directly.` },
      { q: `What is the SNGPL helpline for payment disputes in ${city.name}?`, a: `The 24/7 SNGPL helpline is 1199. For payment tracing, have your consumer number, transaction ID, payment date, amount, and channel ready before calling. The agent logs the dispute and provides a reference number — follow up every 3–5 days if unresolved.` },
      { q: `How do I avoid accidental double payment of my SNGPL bill in ${city.name}?`, a: `Before making a payment, always check the current bill status on the portal — if it shows Rs. 0 outstanding, the bill has already been paid. Set a personal rule: check portal → pay → check portal again after 48 hours to confirm reflection. Do not pay twice just because the portal has not updated yet.` },
      { q: `Is there a way to get a refund if I overpaid my SNGPL bill in ${city.name}?`, a: `SNGPL does not immediately refund overpayments in cash. Overpaid amounts are automatically applied as a credit against your next bill. If you want a cash refund for a significant overpayment, you can request one through selfservice.sngpl.com.pk or at ${city.office} — but the process is lengthy. It is generally easier to let the credit offset future bills.` },
    ],
    default: [
      { q: `What is the easiest way to pay an SNGPL gas bill in ${city.name}?`, a: `Easypaisa and JazzCash are the fastest and most popular payment methods for ${city.name} consumers — available 24/7 on smartphones and via USSD on feature phones. Bank apps (HBL, UBL, MCB, etc.) are also convenient for consumers who prefer their existing banking app.` },
      { q: `Can I pay my SNGPL bill in cash without visiting a bank in ${city.name}?`, a: `Yes. Pay at any Easypaisa or JazzCash franchise counter in ${city.name} — these are widely available in residential areas including ${city.areas}. Bring your consumer number and cash (plus the service fee). The transaction is processed immediately and a receipt is issued.` },
      { q: `What is the best time of day to pay an SNGPL bill to ensure same-day processing in ${city.name}?`, a: `Easypaisa and JazzCash digital payments process 24/7. Bank ATM and internet banking payments made before 3 PM on a working day are typically processed the same day. Payments made after 3 PM or on weekends/holidays process on the next working day.` },
      { q: `Does SNGPL accept advance payment before the bill is generated for ${city.name} consumers?`, a: `Yes. SNGPL accepts advance deposits through selfservice.sngpl.com.pk and at ${city.office}. The advance is held as a credit on your account and deducted from bills as they are generated. This is useful for planning ahead for high winter bills.` },
      { q: `Can someone in another city pay my ${city.name} SNGPL bill remotely?`, a: `Yes. Any Easypaisa, JazzCash, or bank account holder in Pakistan can pay your SNGPL consumer number remotely — geography does not matter. Just share your consumer number with the person making the payment and confirm the amount shown on the portal before they pay.` },
      { q: `What if I pay my SNGPL bill but disconnection happens the same day in ${city.name}?`, a: `Call 1199 immediately with your transaction ID and consumer number. SNGPL field teams can halt a disconnection order on the same day if payment proof is provided. In-person visits to ${city.office} with payment proof receive priority handling for same-day disconnection prevention.` },
    ],
  };
  return map[bucket] ?? map.default;
}

// ─────────────────────────────────────────────────────────────────
// TROUBLESHOOTING FAQs
// ─────────────────────────────────────────────────────────────────
function troubleshootingFaqs(type: string, city: CityData): FaqItem[] {
  const buckets: BucketDef[] = [
    { key: 'high-bill',     matches: ['high-bill', 'overcharge', 'double-charge', 'wrong-amount', 'calculation-error', 'billing-error', 'billing-dispute', 'surcharge-dispute', 'arrears-dispute', 'appeal-bill', 'tariff-increase', 'levy-dispute'] },
    { key: 'no-gas',        matches: ['no-gas', 'gas-disconnected', 'gas-pressure', 'leakage', 'emergency', 'restoration', 'high-consumption', 'seasonal-increase'] },
    { key: 'meter',         matches: ['meter-fault', 'meter-not', 'meter-reading-error', 'meter-change', 'new-meter', 'inspection-request'] },
    { key: 'disconnection', matches: ['disconnection-notice', 'reconnection', 'demand-notice', 'notice-response', 'reconnection-application'] },
    { key: 'complaint',     matches: ['complaint', 'helpline', 'customer-care', 'whatsapp-support', 'online-complaint', 'track-complaint', 'sngpl-portal-complaint'] },
    { key: 'portal-error',  matches: ['bill-not-available', 'website-error', 'bill-not-generated', 'account-issue'] },
    { key: 'payment-issue', matches: ['payment-not-reflected', 'missing-payment', 'refund', 'security-deposit'] },
    { key: 'connection',    matches: ['new-connection', 'connection-transfer', 'address-change', 'name-change', 'connection-issue', 'subsidy'] },
  ];
  const bucket = classify(type, buckets);
  const map: Record<string, FaqItem[]> = {
    'high-bill': [
      { q: `What is the maximum consumption increase I should tolerate before disputing my ${city.name} SNGPL bill?`, a: `A 20% month-on-month increase in HHM consumption during a consistent season (e.g., summer-to-summer) is worth investigating. A 100%+ spike in a single month almost always indicates an estimated reading, meter fault, arrears addition, or genuine leak. Investigate all spikes above 50% before paying without query.` },
      { q: `Can SNGPL back-charge me for gas used 2–3 years ago in ${city.name}?`, a: `SNGPL can issue retrospective bills for previously under-billed or unbilled consumption, but OGRA limits the retrospective billing period. Generally, back-charges beyond 2 years are contestable. If you receive a back-charge with no supporting notice explaining the billing period and reason, call 1199 and request the "arrears advice notice" and calculation methodology.` },
      { q: `How do I calculate my own SNGPL bill to verify the amount charged for ${city.name}?`, a: `Use the bill calculator at /calculator. Enter your opening reading (last month), closing reading (this month), and connection type. Compare the output with your bill — if they match, the calculation is correct. If they differ by more than Rs. 50, file a billing complaint through selfservice.sngpl.com.pk with both figures documented.` },
      { q: `Does the SNGPL helpline 1199 have a dedicated billing dispute line for ${city.name} consumers?`, a: `1199 is the single helpline for all SNGPL services including billing disputes. When connected, select the billing dispute option or ask to be transferred to billing support. Always call during non-peak hours (Tuesday–Thursday, mid-morning) for shorter wait times.` },
      { q: `What happens if SNGPL rejects my billing dispute in ${city.name}?`, a: `If SNGPL's internal process does not resolve the dispute to your satisfaction, escalate to OGRA's consumer affairs department at ogra.org.pk. OGRA has jurisdiction over SNGPL billing disputes and can direct SNGPL to conduct a full audit. Maintain all documentation including your original dispute reference number.` },
      { q: `Can a non-payment of a disputed amount lead to gas disconnection in ${city.name}?`, a: `Yes, if the dispute remains unresolved and unpaid. To protect yourself: pay the undisputed portion, formally log your dispute via selfservice.sngpl.com.pk (this creates a paper trail), and follow up. An active logged dispute provides some protection against disconnection while the investigation is ongoing, but it does not automatically pause disconnection timelines — ask SNGPL explicitly whether a disconnection hold has been placed on your account.` },
    ],
    'no-gas': [
      { q: `How do I report a gas emergency (smell of gas) in ${city.name} to SNGPL?`, a: `Call 1199 immediately. Leave the building first — do not operate any electrical switches. The 1199 emergency line operates 24/7 and dispatches field teams for all gas leak reports in ${city.name} and ${city.division}. Provide your full address including area name, street, and house number.` },
      { q: `How long does SNGPL typically take to restore gas supply after an outage in ${city.name}?`, a: `For planned maintenance outages, SNGPL restores supply by the announced end time. For unplanned pipe ruptures or distribution faults, restoration typically takes 4–24 hours after the fault is located and repaired. Low-pressure issues due to network load take longer to resolve and may persist until the underlying capacity issue is addressed.` },
      { q: `Can I check if there is a planned SNGPL gas outage in my ${city.name} area online?`, a: `Yes. SNGPL posts planned outage notices on its official website (sngpl.com.pk) and official social media pages (Facebook, Twitter). For ${city.division} area-specific notices, monitor the SNGPL Facebook page as it provides the most timely outage announcements.` },
      { q: `My gas pressure is very low in ${city.name} but neighbors have normal supply — what is the issue?`, a: `Low pressure affecting only your connection suggests a problem with your internal pipe, meter valve, or regulator. First, check that your meter shutoff valve is fully open. If the issue persists, call 1199 to request a meter and internal supply inspection — there may be a partial blockage or regulator failure specific to your connection.` },
      { q: `Does SNGPL compensate consumers for loss due to gas outages in ${city.name}?`, a: `SNGPL does not provide financial compensation for revenue loss or inconvenience during gas outages. For lengthy outages exceeding 72 continuous hours, consumers can file a formal complaint with SNGPL and OGRA documenting the impact. Regulatory complaints occasionally result in billing credits at OGRA's direction.` },
      { q: `How do I know if my ${city.name} area is under SNGPL gas load management rotation?`, a: `Check sngpl.com.pk or SNGPL's official Facebook page for the current load management schedule for ${city.division}. The schedule lists affected areas and rotation times. You can also call 1199 and ask whether load management is active in your area of ${city.name}.` },
    ],
    meter: [
      { q: `How do I request a meter inspection from SNGPL for my ${city.name} connection?`, a: `Log into selfservice.sngpl.com.pk, go to "Service Requests," and submit a "Meter Inspection" request with your consumer number and the issue description. Alternatively, call 1199. SNGPL typically sends a field engineer within 3–7 working days. You will receive a complaint reference number to track the request.` },
      { q: `If my SNGPL meter is replaced in ${city.name}, does my consumer number change?`, a: `No. Your consumer number remains the same after a meter replacement. Only the meter serial number changes. The new meter number is updated in SNGPL's system and reflected on future bills. Verify the new meter serial number on your next bill to confirm the update.` },
      { q: `Can I take my own meter reading and submit it to SNGPL in ${city.name}?`, a: `Yes. The SNGPL app has a "Self Meter Reading" feature. Read your meter display (whole number portion only), enter it in the app before the reading cutoff date shown on your bill, and submit. This is especially useful when your meter is difficult for SNGPL's reader to access and you receive repeated estimated readings.` },
      { q: `What is a meter seal and why does it matter for ${city.name} SNGPL consumers?`, a: `SNGPL places a tamper-evident seal on gas meters. If the seal is broken — whether accidentally or by a third party — call 1199 immediately and do not use any gas appliances. A broken seal triggers an investigation for unauthorized gas use. Seals broken by natural wear are replaced by SNGPL during regular inspection with no penalty; tamper-broken seals can result in fines and criminal charges.` },
      { q: `How do I know if my SNGPL meter is recording incorrectly in ${city.name}?`, a: `Compare the reading on your physical meter with the "Current Reading" on your last SNGPL bill. If the physical meter shows significantly less than what was billed (not explained by the reading cycle days), or if the meter dial moves when all appliances are off (indicating a leak), request a meter inspection via 1199 or selfservice.sngpl.com.pk immediately.` },
      { q: `What compensation does SNGPL provide for overbilling due to a faulty meter in ${city.name}?`, a: `If the meter inspection confirms the meter was at fault, SNGPL recalculates the bills for the affected period based on your historical consumption pattern. The over-billed amount is credited to your account and deducted from future bills. You cannot receive a cash refund directly — only a credit adjustment.` },
    ],
    disconnection: [
      { q: `How much time do I have to respond to an SNGPL disconnection notice in ${city.name}?`, a: `SNGPL disconnection notices typically specify a response deadline of 5–15 days. Pay the outstanding amount and call 1199 with your transaction ID before this deadline. Failure to respond results in physical disconnection. Acting immediately upon receiving a notice is critical.` },
      { q: `What is the reconnection fee after SNGPL disconnection in ${city.name}?`, a: `SNGPL reconnection fees vary by account type and how long the disconnection has been in place. For residential consumers, reconnection fees typically range from Rs. 500–2,000. All outstanding dues (bill amounts + late surcharges) must also be paid in full before reconnection is processed. Confirm the exact fee with ${city.office} or 1199.` },
      { q: `Can SNGPL reconnect the same day I pay my outstanding bill in ${city.name}?`, a: `Same-day reconnection is possible in some cases if you pay early in the morning and personally deliver proof of payment to ${city.office}. However, SNGPL's standard processing time for reconnection after payment is 24–72 hours. For faster service, visit the office in person with payment proof rather than relying only on calling 1199.` },
      { q: `Can I dispute a disconnection notice from SNGPL if I believe the bill is wrong in ${city.name}?`, a: `Yes. Immediately call 1199 and file a billing dispute. Request that a "disconnection hold" be placed on your account pending dispute resolution. This is not guaranteed, but logging a formal complaint before the disconnection date can sometimes pause the process. Simultaneously, pay the undisputed amount to demonstrate good faith.` },
      { q: `What documents do I need to apply for SNGPL reconnection in ${city.name}?`, a: `Bring to ${city.office}: original CNIC, your consumer number, proof of all outstanding payments (Easypaisa/JazzCash receipts, bank statement, or ATM receipt), and the reconnection application form (available at the office or on sngpl.com.pk). If any account changes are needed (new owner name, updated mobile), bring those supporting documents as well.` },
      { q: `Does SNGPL disconnect gas for the whole building if one apartment in ${city.name} has unpaid bills?`, a: `No. Each consumer number is billed and managed independently. Disconnection applies only to the specific meter and connection associated with the consumer number that has unpaid dues. If a building has multiple meters, only the defaulting account's supply is disconnected.` },
    ],
    complaint: [
      { q: `What is the fastest way to register an SNGPL complaint from ${city.name}?`, a: `Call 1199 (24/7) — this is the fastest channel for urgent complaints. For non-urgent issues, selfservice.sngpl.com.pk allows you to file with documentation attached. In-person visits to ${city.office} are recommended for complex disputes requiring paperwork.` },
      { q: `How do I track the status of my SNGPL complaint in ${city.name}?`, a: `Your complaint receives a reference number at filing. Track it on selfservice.sngpl.com.pk under "My Complaints" or call 1199 and provide the reference number. The agent will update you on the current status, assigned team, and expected resolution date.` },
      { q: `What is the SNGPL complaint resolution time for ${city.name} consumers?`, a: `Billing complaints: 15–30 working days. Meter inspection requests: 3–7 working days for the inspection, then 5–15 days for any billing correction. Emergency gas/leak issues: same day (4–8 hours). Connection transfer requests: 2–4 weeks. Complex disputes may take longer.` },
      { q: `Can I file an SNGPL complaint via WhatsApp from ${city.name}?`, a: `The SNGPL WhatsApp service is currently bill inquiry only — it does not support complaint registration via WhatsApp messaging. File complaints through selfservice.sngpl.com.pk, by calling 1199, or in person at ${city.office}.` },
      { q: `What if SNGPL does not resolve my complaint within the stated time in ${city.name}?`, a: `If your complaint remains unresolved past the committed resolution date, escalate to OGRA (Oil and Gas Regulatory Authority) at ogra.org.pk. File a consumer complaint with your SNGPL complaint reference number, all documentation, and the dates of your follow-up calls. OGRA has authority to direct SNGPL to prioritize and resolve valid complaints.` },
      { q: `Can I complain about SNGPL field staff behavior in ${city.name}?`, a: `Yes. SNGPL has a customer services team that handles complaints about field staff conduct. File through selfservice.sngpl.com.pk under "Customer Service Complaint" or call 1199 and ask to speak with the Customer Relations department. Provide the date, time, the staff member's identification (ID badge or vehicle number if a field team), and a detailed account of the incident.` },
    ],
    'portal-error': [
      { q: `Why does the SNGPL bill portal show "no record found" for my ${city.name} consumer number?`, a: `Possible reasons: (1) the consumer number is entered incorrectly — recheck all digits including leading zeros; (2) the bill for this month has not been generated yet — check after your reading date; (3) your account may be temporarily inactive — call 1199 to confirm account status; (4) a portal data sync delay — try again after 24 hours.` },
      { q: `The SNGPL website is very slow today in ${city.name} — is there an outage?`, a: `SNGPL does not have an official status page. Portal slowness typically occurs around bill generation dates (when millions of consumers check simultaneously). Try at off-peak hours (early morning or late evening). Use the SNGPL mobile app as an alternative — it typically has faster individual account queries.` },
      { q: `Can I access the SNGPL portal through a VPN if it is blocked in ${city.name}?`, a: `The SNGPL portal is a Pakistan-hosted website accessible without a VPN from within Pakistan. If you are accessing from abroad, a VPN may help if there are regional restrictions. Within Pakistan, VPNs should not be necessary for portal access — if the site is inaccessible, it is a temporary downtime issue.` },
      { q: `The SNGPL bill PDF download fails every time in ${city.name}. What should I fix?`, a: `Try: (1) use Google Chrome or Edge (avoid Firefox for PDF downloads from SNGPL); (2) disable pop-up blockers — the PDF opens in a new tab that may be blocked; (3) clear browser cache and try again; (4) on mobile, enable desktop mode or switch to the SNGPL app to download the bill.` },
      { q: `My SNGPL app shows "something went wrong" when I try to view my ${city.name} bill. What should I do?`, a: `Force-close the app, check your internet connection, then reopen. If the error persists, clear the app cache (Settings → Apps → SNGPL → Clear Cache on Android). If it still fails, uninstall and reinstall the app — your bill history reloads from the server after re-login.` },
      { q: `Why does the SNGPL portal show last month's bill instead of this month's for ${city.name}?`, a: `This month's bill has not been generated yet. SNGPL only generates the bill after your meter reading date. Until the new bill is generated, the portal displays the most recently generated one. Check back after your reading date (visible on last month's bill).` },
    ],
    'payment-issue': [
      { q: `How long does an SNGPL payment refund take if I overpaid in ${city.name}?`, a: `SNGPL applies overpayments as credit against future bills — this typically appears on the next monthly bill as "Advance Payment Credit." A cash refund is theoretically available by request at ${city.office}, but the process is lengthy (6–12 weeks or more) and it is easier to let the credit offset future payments.` },
      { q: `What is the SNGPL security deposit and can I get it back in ${city.name}?`, a: `When a new gas connection is issued in ${city.name}, SNGPL collects a security deposit (typically 1–3 months of estimated consumption). The deposit is refunded when the connection is permanently surrendered (meter removed, account closed) after deducting any outstanding dues. The refund process takes 30–90 days after surrender application.` },
      { q: `Can I use my SNGPL security deposit to pay a bill I cannot afford in ${city.name}?`, a: `No. The security deposit is held by SNGPL as financial security for the connection and cannot be applied toward current bill payments while the connection is active. It is only released upon connection surrender.` },
      { q: `My SNGPL payment via bank transfer has not reflected after 5 days in ${city.name}. What should I do?`, a: `After 72 hours, contact your bank first with the transaction ID to confirm the payment was dispatched. If the bank confirms dispatch, call SNGPL 1199 with: consumer number, bank name, transaction date, amount, and bank reference number. SNGPL's payment operations team can manually trace and post the payment.` },
      { q: `Can a fraudulent SNGPL payment deduction happen from my Easypaisa account in ${city.name}?`, a: `If you only enter your consumer number in the official Easypaisa app and no unusual deductions occur, your account is safe. Never share your Easypaisa PIN with anyone. If an unauthorized SNGPL payment appears in your Easypaisa transaction history, report it to Easypaisa customer service (042-111-003-737) immediately for fraud investigation.` },
      { q: `How do I request a payment history statement from SNGPL for my ${city.name} account?`, a: `Log into selfservice.sngpl.com.pk and navigate to "Payment History" or "Account Statement." You can typically view and download the last 12 months of payment records. For statements older than 12 months (e.g., for legal or property proceedings), visit ${city.office} with a written request specifying the required period.` },
    ],
    connection: [
      { q: `How do I apply for a new SNGPL gas connection in ${city.name}?`, a: `Visit ${city.office} with: your original CNIC, proof of property ownership or tenancy agreement, site plan or address proof, and the connection application form. SNGPL conducts a site survey, calculates the connection fee, and issues a demand notice. Standard residential connections in established pipeline areas take 30–90 days.` },
      { q: `What are the SNGPL new connection charges in ${city.name}?`, a: `New connection charges include a connection fee determined by the pipeline distance from the main, a security deposit (1–3 months of estimated consumption), and meter cost. Exact amounts are advised by ${city.office} after the site survey. Call 1199 for a general estimate for your area.` },
      { q: `Does ${city.name} have a waiting list for new SNGPL gas connections?`, a: `In areas of ${city.name} where existing pipeline capacity is fully utilized, SNGPL may place new connection applications on a waiting list pending network expansion. Check the current status with ${city.office} for your specific locality within ${city.areas}.` },
      { q: `What is the SNGPL subsidy for new gas connections in ${city.province}?`, a: `Government subsidy programs for SNGPL connections (Ehsaas program, low-income housing schemes) are announced periodically. Eligibility is based on income level and registration in relevant government databases. Monitor sngpl.com.pk and the ${city.division} regional office notice boards for current active subsidy schemes.` },
      { q: `How do I change my registered address in the SNGPL system for ${city.name}?`, a: `Address changes are possible when a connection is transferred from one property to another (new connection at new address). A gas connection cannot be "moved" — it is tied to a specific meter at a specific property. If you relocate in ${city.name}, you need a new connection at the new address and formally surrender the old connection.` },
      { q: `Can I temporarily suspend my SNGPL connection in ${city.name} if I am going abroad?`, a: `SNGPL does not offer a formal temporary suspension service. You can ensure bills are monitored and paid in your absence by authorizing a trusted person or sharing your Easypaisa auto-pay setup. Consider registering on selfservice.sngpl.com.pk to monitor your account remotely. Contact ${city.office} to discuss options for extended absence situations.` },
    ],
    default: [
      { q: `What is the SNGPL 24-hour helpline number for ${city.name} consumers?`, a: `The SNGPL helpline is 1199, available 24 hours a day, 7 days a week. It handles all types of queries: billing disputes, payment issues, gas outages, leak emergencies, new connections, meter problems, and complaint tracking. Always have your consumer number ready when calling.` },
      { q: `Can I file an SNGPL complaint online from ${city.name} without visiting an office?`, a: `Yes. selfservice.sngpl.com.pk provides an online complaint portal. Register with your CNIC, select your consumer number, choose the complaint category, describe the issue, attach any supporting documents (meter photos, bill scans), and submit. You receive a reference number for tracking.` },
      { q: `How do I know my SNGPL complaint has been received in ${city.name}?`, a: `After filing through selfservice.sngpl.com.pk, you receive a complaint reference number on-screen and via SMS to your registered mobile. If you filed by phone (1199), the agent provides a reference number verbally — write it down immediately. This number is your only tracking tool.` },
      { q: `What types of SNGPL issues cannot be resolved by calling 1199 in ${city.name}?`, a: `1199 can initiate most requests, but these require in-person visits to ${city.office}: connection transfer documentation, certified bill collection, security deposit refunds, new connection applications, and any issue requiring physical signature or CNIC verification. 1199 can tell you exactly what you need to bring.` },
      { q: `Is there an SNGPL WhatsApp number for troubleshooting in ${city.name}?`, a: `SNGPL's official WhatsApp service is currently limited to bill inquiries. For troubleshooting, complaint registration, meter issues, and account problems, use the 1199 helpline or selfservice.sngpl.com.pk.` },
      { q: `How do I prevent recurring SNGPL billing problems in ${city.name}?`, a: `Best practices: (1) register on selfservice.sngpl.com.pk to monitor your account digitally, (2) install the SNGPL app and enable bill notifications, (3) take and save a monthly photo of your meter reading before the billing date, (4) pay 3–5 days before the due date, (5) save all payment receipts digitally, (6) check the portal 48 hours after payment to confirm the balance dropped to zero.` },
    ],
  };
  return map[bucket] ?? map.default;
}

// ─────────────────────────────────────────────────────────────────
// PUBLIC: getTypeFocusFaqs
// ─────────────────────────────────────────────────────────────────
export function getTypeFocusFaqs(
  type: string,
  city: CityData,
  category: 'bill-check' | 'consumer-number' | 'duplicate-bill' | 'payment' | 'troubleshooting'
): FaqItem[] {
  switch (category) {
    case 'bill-check':      return billCheckFaqs(type, city);
    case 'consumer-number': return consumerNumberFaqs(type, city);
    case 'duplicate-bill':  return duplicateBillFaqs(type, city);
    case 'payment':         return paymentFaqs(type, city);
    case 'troubleshooting': return troubleshootingFaqs(type, city);
    default:                return billCheckFaqs(type, city);
  }
}

// ─────────────────────────────────────────────────────────────────
// PUBLIC: getCommonMistakesSection
// ─────────────────────────────────────────────────────────────────
export function getCommonMistakesSection(
  city: CityData,
  category: 'bill-check' | 'consumer-number' | 'duplicate-bill' | 'payment' | 'troubleshooting'
): ContentSection {
  const sections: Record<string, ContentSection> = {
    'bill-check': {
      h2: `Common SNGPL Bill Check Mistakes Made by ${city.name} Consumers`,
      body: `These are the most frequent errors ${city.name} consumers make when checking their SNGPL gas bill — and how to avoid each one.

**Mistake 1: Using unofficial third-party websites.** Many websites rank for "SNGPL bill check" but are not official SNGPL portals. Always use billchecker.sngpl.com.pk — the only official SNGPL bill checking website. Third-party sites may show outdated data or insert ads. This site redirects you to the official portal.

**Mistake 2: Ignoring leading zeros in the consumer number.** SNGPL consumer numbers must be entered exactly as printed on the bill. Dropping a leading zero (e.g., entering 1234567890 instead of 01234567890) returns a "not found" error or retrieves the wrong account. Count every digit on your bill carefully.

**Mistake 3: Checking the bill only when it arrives by post.** Postal delivery to ${city.areas} can take 5–15 days after generation. By then, the due date may be less than a week away. Install the SNGPL app and enable notifications so you see the bill within 24 hours of generation — giving you 15–20 days to arrange payment.

**Mistake 4: Confusing the meter number with the consumer number.** The meter serial number (stamped on the physical device) is not the same as the consumer number used for bill checks and payments. Using the meter number on the payment portal produces an error. Always use the consumer number from your bill.

**Mistake 5: Not downloading a copy before paying.** After paying, the portal may temporarily show the bill as "paid" or no bill at all. Download the PDF before paying so you have a record of what was owed and when it was due, which is useful if there is any payment dispute.

**Mistake 6: Not verifying payment reflection.** Many ${city.name} consumers assume payment is confirmed when Easypaisa shows success. Always check the SNGPL portal 24–48 hours after payment to confirm the balance has dropped to zero. If it has not, you have your payment receipt to escalate with 1199.`,
    },
    'consumer-number': {
      h2: `Common SNGPL Consumer Number Mistakes Made by ${city.name} Consumers`,
      body: `These mistakes with SNGPL consumer numbers are surprisingly common across ${city.name} — and often lead to misrouted payments or failed transactions.

**Mistake 1: Using the meter number instead of the consumer number.** The meter serial number is on the meter body. The consumer number is on your bill. They are completely different numbers. The consumer number is the only valid identifier for payments and bill inquiries.

**Mistake 2: Dropping leading zeros.** If your consumer number is 0123456789, entering 123456789 (without the leading zero) either returns an error or finds a completely different account. Always enter the full number including all leading zeros exactly as printed.

**Mistake 3: Assuming the consumer number changes when the meter is replaced.** Your consumer number is tied to your address and account — not to the physical meter. Meter replacements due to fault, calibration, or upgrade do not change your consumer number. Payments continue using the same number.

**Mistake 4: Sharing consumer number carelessly.** While the consumer number alone cannot authorize account changes (which require CNIC verification), it exposes your billing details to anyone who has it. Avoid posting your consumer number publicly or sharing it with unofficial parties claiming to check bills on your behalf.

**Mistake 5: Not saving the consumer number in multiple places.** Many ${city.name} consumers keep the consumer number only on their gas bill. When bills are lost or not received by post, they have to call 1199 or visit ${city.office} to recover it. Save it in your phone contacts, a note app, and take a photo of your meter card.

**Mistake 6: Using another family member's consumer number by mistake.** If you manage multiple connections (e.g., home and shop in ${city.areas}), always double-check which consumer number you are entering before making a payment. A misdirected payment to the wrong consumer number can take weeks to rectify.`,
    },
    'duplicate-bill': {
      h2: `Common SNGPL Duplicate Bill Mistakes Made by ${city.name} Consumers`,
      body: `Getting a duplicate SNGPL bill should be a two-minute task. These mistakes unnecessarily complicate the process for ${city.name} consumers.

**Mistake 1: Visiting ${city.office} for a bill that is available online.** The current month's duplicate bill is downloadable at billchecker.sngpl.com.pk in under two minutes — for free, 24/7. Many consumers waste half a day visiting the office for something they could get on their phone. Only visit for certified copies, bills older than 12 months, or legally stamped documents.

**Mistake 2: Using the browser history link for repeated downloads.** The portal generates a fresh bill each time based on the current database. Bookmarking the results page URL (with your consumer number in the URL) may not work reliably. Bookmark the homepage and re-enter your consumer number each time for a fresh, current bill.

**Mistake 3: Printing bills with "Print to PDF" from desktop apps instead of the browser PDF download.** Some word processor print-to-PDF functions create a visually distorted version. Always use your browser's built-in Save as PDF or the portal's "Download PDF" button for a clean, institution-ready copy.

**Mistake 4: Downloading last month's bill thinking it is this month's.** The portal only shows the most recently generated bill. If the new bill has not yet been generated for this month, the previous month's bill appears. Check the billing period on the bill header carefully before using it for any institutional submission.

**Mistake 5: Not enabling bill history in the SNGPL app.** If you have not registered on the SNGPL app, you have no access to previous months' bills other than visiting ${city.office}. Register on the app now — it builds your 12-month history going forward, saving future trips for archive requests.

**Mistake 6: Accepting a photocopy of a bill from a landlord instead of downloading a fresh copy.** A photocopy of a physical bill may be old, faded, or altered. Always download a fresh, official duplicate from the portal for any submission — it is newer, clearer, and unquestionably official.`,
    },
    payment: {
      h2: `Common SNGPL Bill Payment Mistakes Made by ${city.name} Consumers`,
      body: `These payment errors cost ${city.name} consumers money in unnecessary surcharges and cause serious stress around disconnection deadlines.

**Mistake 1: Paying on the due date itself.** Easypaisa and JazzCash payments take 24–48 hours to reflect in SNGPL's system. If you pay on the due date and the payment does not process until midnight or after, the 10% late surcharge is automatically applied. Pay at least 3 days before the due date.

**Mistake 2: Entering the consumer number incorrectly.** A single wrong digit routes your payment to a different consumer's account. Before confirming any SNGPL payment on Easypaisa, JazzCash, or any bank app, compare the amount shown by the app with the amount on your bill — a mismatch is the clearest sign of a wrong consumer number.

**Mistake 3: Not saving the transaction ID immediately.** After paying on Easypaisa or JazzCash, a transaction confirmation screen appears for a few seconds. Many consumers dismiss it without noting the transaction ID. If the payment later does not reflect, this ID is essential for tracing it with SNGPL. Screenshot the confirmation screen every time.

**Mistake 4: Paying the wrong amount.** Some consumers pay a round number (e.g., Rs. 2,000) when the actual bill is Rs. 2,156. The remaining Rs. 156 carries forward as arrears on the next bill. Always check the exact bill amount on the portal before initiating payment — then enter that exact figure.

**Mistake 5: Paying twice after a portal delay.** When the portal does not immediately reflect a payment, some consumers pay again — creating a double payment. The second payment becomes a credit on the next bill, but the first month still shows an apparent outstanding until clearing. Always wait 72 hours and check the portal before paying a second time.

**Mistake 6: Ignoring a disconnection notice hoping it will resolve itself.** SNGPL does not withdraw disconnection notices automatically. Any disconnection notice received must be responded to within the specified deadline — either by paying in full or by calling 1199 before the deadline to arrange an extension. Ignoring the notice guarantees disconnection.`,
    },
    troubleshooting: {
      h2: `Common SNGPL Troubleshooting Mistakes Made by ${city.name} Consumers`,
      body: `When dealing with SNGPL problems, these mistakes by ${city.name} consumers often make situations worse or cause unnecessary delays.

**Mistake 1: Withholding full payment during a billing dispute without documentation.** Not paying while disputing a bill can lead to disconnection even if your dispute is valid. Always pay the undisputed amount and formally log the dispute through selfservice.sngpl.com.pk — creating a paper trail is your protection.

**Mistake 2: Not photographing the meter before and after reporting an issue.** If you report a meter fault, estimated reading, or gas leak, photographic evidence of the meter display at the time of the report is critical. A timestamped photograph can make the difference between a valid and a dismissed claim.

**Mistake 3: Calling 1199 without a complaint reference number for follow-up.** When calling 1199 for an ongoing issue, always provide your original complaint reference number from the first call. Without it, agents cannot locate your file and you may receive an unhelpful generic response or be asked to re-file.

**Mistake 4: Assuming a gas smell is a billing issue.** Never ignore the smell of gas. Do not call 1199 for billing support when you smell gas — this is an emergency. Leave the building immediately, do not operate any switches, and call 1199 emergency. A billing dispute can wait; a gas leak cannot.

**Mistake 5: Not escalating to OGRA when SNGPL disputes are unresolved.** Many ${city.name} consumers spend months repeatedly calling 1199 without resolution. If SNGPL has not resolved a valid complaint within 30 working days, file a formal complaint with OGRA at ogra.org.pk — SNGPL's regulatory oversight body with authority to direct resolution.

**Mistake 6: Accepting verbal promises from SNGPL field staff.** Field teams sometimes verbally promise billing corrections, meter inspections, or reconnection timelines that do not materialize. Always request a written complaint number for every service interaction and follow up via the portal — verbal commitments are not binding.`,
    },
  };
  return sections[category] ?? sections['bill-check'];
}
